<?php
declare(strict_types=1);
if(PHP_SAPI!=='cli'){exit(2);}require_once dirname(__DIR__).'/lib/config.php';require_once dirname(__DIR__).'/lib/Database.php';
$pdo=new PDO(DB_DSN,DB_USERNAME,DB_PASSWORD,[PDO::ATTR_ERRMODE=>PDO::ERRMODE_EXCEPTION]);$admin=$pdo->query("SELECT u_id FROM user_tbl WHERE u_type=1 AND avail_status=1 ORDER BY u_id LIMIT 1")->fetchColumn();if(!is_string($admin)||$admin===''){exit(1);}$session=hash('sha256','f74-session');$browser=hash('sha256','f74-browser');$op=new Database();$ids=[];$ok=false;
try{$op->beginTransaction();foreach(['ADMIN_ACCESS','SECURITY_CONFIGURATION_CHANGE','ACTIVE_SESSION_REVOCATION'] as $purpose){$id=bin2hex(random_bytes(32));$ids[]=$id;$op->admin_step_up_create_grant(['grant_id'=>$id,'admin_user_id'=>$admin,'session_binding_hash'=>$session,'browser_digest'=>$browser,'purpose'=>$purpose,'verified_factor'=>'TOTP','correlation_id'=>bin2hex(random_bytes(8))]);}$adminState=$op->admin_step_up_authorization_state($admin,$session,$browser,'ADMIN_ACCESS');$configState=$op->admin_step_up_authorization_state($admin,$session,$browser,'SECURITY_CONFIGURATION_CHANGE');$wrongBrowser=$op->admin_step_up_authorization_state($admin,$session,hash('sha256','other'),'ADMIN_ACCESS');$ok=(int)$adminState['exact_valid']===1&&(int)$adminState['other_valid']===2&&(int)$configState['exact_valid']===1&&(int)$configState['other_valid']===2&&(int)($wrongBrowser['exact_valid']??0)===0;}finally{$op->rollback();}
$marks=implode(',',array_fill(0,count($ids),'?'));$q=$pdo->prepare("SELECT COUNT(*) FROM admin_step_up_grants WHERE grant_id IN ($marks)");$q->execute($ids);$remaining=(int)$q->fetchColumn();printf("%s exact_purpose=%s browser_isolated=%s rollback_remaining=%d persistent_mutations=0\n",$ok&&$remaining===0?'PASS':'FAIL',$ok?'yes':'no',(int)($wrongBrowser['exact_valid']??0)===0?'yes':'no',$remaining);exit($ok&&$remaining===0?0:1);
